import { forwardRef, type PropsWithChildren } from "react";
import { useSeparator } from "../../factory";
import type {IGridItemComponent, IStyleClasses} from "@lmb-it/kitsconcerto-types";
import {useResponsiveBuilder} from "@lmb-it/kitsconcertomobile";

type IsolatedGridItem = Omit<IGridItemComponent, keyof IStyleClasses>

export const pickFirstResponsive = <T,>(v: any): T | undefined => {
    if (v == null) return undefined;
    if (Array.isArray(v)) return v[0] as T;
    if (typeof v === "object") {
        const order = ["base", "sm", "md", "lg", "xl", "xxl", "xxxl"];
        for (const k of order) if (k in v) return v[k] as T;
        const first = Object.values(v)[0];
        return first as T;
    }
    return v as T;
};

const GridItem = forwardRef<any, PropsWithChildren<IGridItemComponent>>((props, ref) => {
    const { cssProps, nativeProps } = useSeparator<IGridItemComponent>(props);
    const { children, className, _extra, ...rest } = nativeProps;

    // derive col-span count
    const colSpan =
        rest.colSpan ??
        pickFirstResponsive<number | string>(cssProps.colSpan) ??
        pickFirstResponsive<number | string>((cssProps as any).gridColumn);

    const colSpanClass =
        typeof colSpan === "number"
            ? `col-span-${colSpan}`
            : typeof colSpan === "string" && colSpan.includes("col-span-")
                ? colSpan
                : '';


    return useResponsiveBuilder<IsolatedGridItem>(
        {
            as: "GridItem",
            cssProps,
            additionalClasses: className,
            nativeProps: {
                ...rest,
                _extra: {
                    ...(typeof _extra === "object" ? _extra : {}),
                    className: colSpanClass,
                },
            },
            children,
        },
        ref
    );
});

export default GridItem;
